#[test]
fn test_blocked_updates_after_dep_add() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    let a = create_issue(&beads_dir, "Issue A");
    let b = create_issue(&beads_dir, "Issue B");

    // Initially B is not blocked
    br_cmd(&beads_dir)
        .arg("blocked")
        .assert()
        .success()
        .stdout(predicate::str::contains("No blocked"));

    // Add dependency
    br_cmd(&beads_dir)
        .args(["dep", "add", &b, &a])
        .assert()
        .success();

    // Now B should be blocked
    br_cmd(&beads_dir)
        .arg("blocked")
        .assert()
        .success()
        .stdout(predicate::str::contains("Issue B"));
}

#[test]
fn test_blocked_updates_after_close() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    let blocker = create_issue(&beads_dir, "Blocker");
    let blocked = create_issue(&beads_dir, "Blocked");

    br_cmd(&beads_dir)
        .args(["dep", "add", &blocked, &blocker])
        .assert()
        .success();

    // Blocked should show up
    br_cmd(&beads_dir)
        .arg("blocked")
        .assert()
        .stdout(predicate::str::contains("Blocked"));

    // Close the blocker
    br_cmd(&beads_dir)
        .args(["close", &blocker])
        .assert()
        .success();

    // Now blocked list should be empty
    br_cmd(&beads_dir)
        .arg("blocked")
        .assert()
        .success()
        .stdout(predicate::str::contains("No blocked"));
}
